import{_ as t,o as a,c as o,a5 as i}from"./chunks/framework.BXfsq1AV.js";const u=JSON.parse('{"title":"Home Screen","description":"","frontmatter":{},"headers":[],"relativePath":"guide/homescreen.md","filePath":"guide/homescreen.md"}'),n={name:"guide/homescreen.md"};function r(s,e,c,l,d,h){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="home-screen" tabindex="-1">Home Screen <a class="header-anchor" href="#home-screen" aria-label="Permalink to “Home Screen”">​</a></h1><p>The Milki Launcher home screen is your curated command center. Place anything under your fingertips—apps, app shortcuts, files, contacts, and widgets—and customize every gesture to match your workflow.</p><h2 id="placing-items" tabindex="-1">Placing Items <a class="header-anchor" href="#placing-items" aria-label="Permalink to “Placing Items”">​</a></h2><p>Your home screen supports a variety of item types. Simply drag anything from the search dialog or app drawer onto the home screen to place it.</p><h3 id="app-icons" tabindex="-1">App Icons <a class="header-anchor" href="#app-icons" aria-label="Permalink to “App Icons”">​</a></h3><p>Place your most-used apps front and center. Long-press any app from the search dialog or the drawer and drag it to your desired spot.</p><div class="tip custom-block github-alert"><p class="custom-block-title">Placeholder: GIF</p><p>Show a GIF of dragging an app icon from the drawer onto the home screen and dropping it into a grid cell.</p></div><h3 id="file-icons" tabindex="-1">File Icons <a class="header-anchor" href="#file-icons" aria-label="Permalink to “File Icons”">​</a></h3><p>Quick-access files can live right on your home screen. Documents, PDFs, downloads—whatever you reach for often.</p><div class="tip custom-block github-alert"><p class="custom-block-title">Placeholder: Screenshot</p><p>Add a screenshot showing file icons (PDF, image, document) alongside app icons on the home screen.</p></div><h3 id="contact-icons" tabindex="-1">Contact Icons <a class="header-anchor" href="#contact-icons" aria-label="Permalink to “Contact Icons”">​</a></h3><p>Pin your most frequent contacts for one-tap calling.</p><div class="tip custom-block github-alert"><p class="custom-block-title">Placeholder: Screenshot</p><p>Add a screenshot showing contact icons with avatars displayed on the home screen.</p></div><h3 id="folders" tabindex="-1">Folders <a class="header-anchor" href="#folders" aria-label="Permalink to “Folders”">​</a></h3><p>Group related items together. Drag one item on top of another to create a folder, then drag additional items in.</p><div class="tip custom-block github-alert"><p class="custom-block-title">Placeholder: GIF</p><p>Show a GIF of creating a folder by dragging one app icon onto another, then adding more items into it.</p></div><h2 id="no-duplicates" tabindex="-1">No Duplicates <a class="header-anchor" href="#no-duplicates" aria-label="Permalink to “No Duplicates”">​</a></h2><p>Milki prevents duplicate items on the home screen. If you drag an existing item from one cell to another, it <strong>moves</strong> instead of copying. This keeps your home screen clean and intentional.</p><div class="tip custom-block github-alert"><p class="custom-block-title">Placeholder: GIF</p><p>Show a GIF of dragging an already-placed app icon from one cell to a different cell, demonstrating it moves rather than duplicates.</p></div><h2 id="widgets" tabindex="-1">Widgets <a class="header-anchor" href="#widgets" aria-label="Permalink to “Widgets”">​</a></h2><p>Milki supports two widget styles so you can choose what fits your layout.</p><h3 id="inline-widgets" tabindex="-1">Inline Widgets <a class="header-anchor" href="#inline-widgets" aria-label="Permalink to “Inline Widgets”">​</a></h3><p>The actual widget is rendered directly in the home screen grid.</p><div class="tip custom-block github-alert"><p class="custom-block-title">Placeholder: Screenshot</p><p>Add a screenshot showing an inline weather widget and an inline music player widget embedded directly in the home screen grid.</p></div><h3 id="popup-widgets" tabindex="-1">Popup Widgets <a class="header-anchor" href="#popup-widgets" aria-label="Permalink to “Popup Widgets”">​</a></h3><p>A single cell icon represents a widget. Tap it and the full widget expands as an overlay. Great for widgets you use occasionally but don&#39;t want taking up permanent space for efficient use of space.</p><div class="tip custom-block github-alert"><p class="custom-block-title">Placeholder: GIF</p><p>Show a GIF of tapping a popup widget icon and the widget expanding as an overlay, then dismissing it.</p></div><h2 id="gesture-actions" tabindex="-1">Gesture Actions <a class="header-anchor" href="#gesture-actions" aria-label="Permalink to “Gesture Actions”">​</a></h2><p>Customize what happens when you interact with the home screen. Every gesture (trigger) can be mapped to any action.</p><h3 id="available-gestures" tabindex="-1">Available Gestures <a class="header-anchor" href="#available-gestures" aria-label="Permalink to “Available Gestures”">​</a></h3><table tabindex="0"><thead><tr><th>Gesture</th><th>Description</th></tr></thead><tbody><tr><td>One Tap</td><td>Single tap on an empty area</td></tr><tr><td>Double Tap</td><td>Two quick taps on an empty area</td></tr><tr><td>Swipe Up</td><td>Swipe upward from the bottom/middle</td></tr><tr><td>Swipe Down</td><td>Swipe downward from the top/middle</td></tr></tbody></table><p>More gestures are planned for future releases.</p><h3 id="available-actions" tabindex="-1">Available Actions <a class="header-anchor" href="#available-actions" aria-label="Permalink to “Available Actions”">​</a></h3><p>Each gesture can be mapped to one of the following actions:</p><table tabindex="0"><thead><tr><th>Action</th><th>What It Does</th></tr></thead><tbody><tr><td>Show Notifications</td><td>Expands the notification panel</td></tr><tr><td>Open Drawer</td><td>Opens the app drawer</td></tr><tr><td>Open App</td><td>Launches a specific app of your choice</td></tr><tr><td>Open App Shortcut</td><td>Launches a specific app shortcut of your choice</td></tr><tr><td>Lock Screen</td><td>Locks the device</td></tr><tr><td>Do Nothing</td><td>Disables the gesture</td></tr></tbody></table><h2 id="interacting-with-the-home-screen" tabindex="-1">Interacting with the Home Screen <a class="header-anchor" href="#interacting-with-the-home-screen" aria-label="Permalink to “Interacting with the Home Screen”">​</a></h2><h3 id="home-button" tabindex="-1">Home Button <a class="header-anchor" href="#home-button" aria-label="Permalink to “Home Button”">​</a></h3><p>Tapping the home button instantly opens the Search Dialog, putting your command center one tap away.</p><div class="tip custom-block github-alert"><p class="custom-block-title">Placeholder: GIF</p><p>Show a GIF of tapping the home button and the Search Dialog sliding up.</p></div><h3 id="context-menu" tabindex="-1">Context Menu <a class="header-anchor" href="#context-menu" aria-label="Permalink to “Context Menu”">​</a></h3><p>Long-press on any empty area of the home screen to open the context menu. From here you can:</p><ul><li><strong>Open Settings</strong></li><li><strong>Open Widget Picker</strong> to add a new widget</li></ul><div class="tip custom-block github-alert"><p class="custom-block-title">Placeholder: GIF</p><p>Show a GIF of long-pressing an empty area, the context menu appearing, and selecting &quot;Widget Picker.&quot;</p></div><h3 id="app-shortcuts" tabindex="-1">App Shortcuts <a class="header-anchor" href="#app-shortcuts" aria-label="Permalink to “App Shortcuts”">​</a></h3><p>Long-press any app icon to open its context menu, which displays available app shortcuts provided by the app. You can drag any of these shortcuts and drop them onto the home screen to create a dedicated icon for quick access.</p><div class="tip custom-block github-alert"><p class="custom-block-title">Placeholder: GIF</p><p>Show a GIF of long-pressing an app icon, revealing shortcuts, and dragging one shortcut onto an empty cell to create a standalone icon.</p></div>',46)])])}const m=t(n,[["render",r]]);export{u as __pageData,m as default};
